a {
  text-decoration: underline; /* Ensure underline is present */
  text-underline-offset: 0.2em; /* Adjusts vertical position to avoid descenders */
  text-decoration-thickness: 0.08em; /* Sets initial thickness */
  text-decoration-color: var(--primary-color, currentColor); /* Optional: customize color */
  transition: text-decoration-color 0.2s ease-in-out, text-decoration-thickness 0.2s ease-in-out;
}

a:hover {
  text-decoration-thickness: 0.15em; /* Thicker on hover for subtle interaction */
}
